INSERT INTO public.course_lessons (id, category_id, sort_order, payload) VALUES ('lesson_greetings_1', 'cat_greetings', 0, $j${"id": "lesson_greetings_1", "category_id": "cat_greetings", "title_ru": "Приветствия и знакомство", "title_en": "Greetings & Introductions", "order": 0, "theory": {"title_ru": "Приветствия в межславянском", "title_en": "Greetings in Interslavic", "blocks": [{"type": "text", "content_ru": "В межславянском языке приветствия очень похожи на те, что используются в других славянских языках. Это делает их легко узнаваемыми.", "content_en": "In Interslavic, greetings are very similar to those used in other Slavic languages. This makes them easily recognizable."}, {"type": "vocabulary_table", "items": [{"isv_lat": "Zdrav budi!", "isv_cyr": "Здрав буди!", "ru": "Здравствуй!", "en": "Hello!"}, {"isv_lat": "Dobry denj!", "isv_cyr": "Добры день!", "ru": "Добрый день!", "en": "Good day!"}, {"isv_lat": "Dobro jutro!", "isv_cyr": "Добро јутро!", "ru": "Доброе утро!", "en": "Good morning!"}, {"isv_lat": "Dobry večer!", "isv_cyr": "Добры вечер!", "ru": "Добрый вечер!", "en": "Good evening!"}, {"isv_lat": "Do viděnja!", "isv_cyr": "До видєња!", "ru": "До свидания!", "en": "Goodbye!"}, {"isv_lat": "Prosim", "isv_cyr": "Просим", "ru": "Пожалуйста", "en": "Please"}, {"isv_lat": "Hvala", "isv_cyr": "Хвала", "ru": "Спасибо", "en": "Thank you"}, {"isv_lat": "Da", "isv_cyr": "Да", "ru": "Да", "en": "Yes"}, {"isv_lat": "Ne", "isv_cyr": "Не", "ru": "Нет", "en": "No"}]}, {"type": "tip", "content_ru": "Обратите внимание: многие слова похожи на русские! Корни слов общие для славянских языков.", "content_en": "Notice: many words look similar to Russian! Word roots are shared across Slavic languages."}]}, "exercises": [{"type": "word_match", "instruction_ru": "Соедините слова с их переводом", "instruction_en": "Match words with their translation", "pairs": [{"isv_lat": "Zdrav budi!", "isv_cyr": "Здрав буди!", "ru": "Здравствуй!", "en": "Hello!"}, {"isv_lat": "Hvala", "isv_cyr": "Хвала", "ru": "Спасибо", "en": "Thank you"}, {"isv_lat": "Prosim", "isv_cyr": "Просим", "ru": "Пожалуйста", "en": "Please"}, {"isv_lat": "Do viděnja!", "isv_cyr": "До видєња!", "ru": "До свидания!", "en": "Goodbye!"}], "hint_ru": "Подумайте о похожих словах в русском языке Сверьтесь с таблицей теории: Zdrav budi!, Dobry denj!, Dobro jutro!, Dobry večer!, Do viděnja!, Prosim, Hvala, Da, Ne (Здравствуй!, Добрый день!, Доброе утро!, Добрый вечер!, До свидания!, Пожалуйста, Спасибо, Да, Нет).", "hint_en": "Think about similar words in Russian  Check the lesson vocabulary: Zdrav budi!, Dobry denj!, Dobro jutro!, Dobry večer!, Do viděnja!, Prosim, Hvala, Da, Ne.", "xp": 10}, {"type": "multiple_choice", "instruction_ru": "Переведите фразу", "instruction_en": "Translate the phrase", "question_isv_lat": "Dobry denj!", "question_isv_cyr": "Добры день!", "options_ru": ["Добрый день!", "Доброе утро!", "Добрый вечер!", "До свидания!"], "options_en": ["Good day!", "Good morning!", "Good evening!", "Goodbye!"], "correct_index": 0, "hint_ru": "Слово 'denj' похоже на русское 'день' Сверьтесь с таблицей теории: Zdrav budi!, Dobry denj!, Dobro jutro!, Dobry večer!, Do viděnja!, Prosim, Hvala, Da, Ne (Здравствуй!, Добрый день!, Доброе утро!, Добрый вечер!, До свидания!, Пожалуйста, Спасибо, Да, Нет).", "hint_en": "The word 'denj' is similar to the Russian 'den' (day)  Check the lesson vocabulary: Zdrav budi!, Dobry denj!, Dobro jutro!, Dobry večer!, Do viděnja!, Prosim, Hvala, Da, Ne.", "xp": 10}, {"type": "fill_blank", "instruction_ru": "Заполните пропуск", "instruction_en": "Fill in the blank", "sentence_isv_lat": "Dobro ___!", "sentence_isv_cyr": "Добро ___!", "answer_isv_lat": "jutro", "answer_isv_cyr": "јутро", "translation_ru": "Доброе утро!", "translation_en": "Good morning!", "hint_ru": "Это слово означает 'утро' и похоже на русское слово Сверьтесь с таблицей теории: Zdrav budi!, Dobry denj!, Dobro jutro!, Dobry večer!, Do viděnja!, Prosim, Hvala, Da, Ne (Здравствуй!, Добрый день!, Доброе утро!, Добрый вечер!, До свидания!, Пожалуйста, Спасибо, Да, Нет).", "hint_en": "This word means 'morning' and sounds similar to the Russian word  Check the lesson vocabulary: Zdrav budi!, Dobry denj!, Dobro jutro!, Dobry večer!, Do viděnja!, Prosim, Hvala, Da, Ne.", "xp": 15}, {"type": "text_input", "instruction_ru": "Напишите перевод на межславянском", "instruction_en": "Write the translation in Interslavic", "prompt_ru": "Спасибо", "prompt_en": "Thank you", "answer_isv_lat": "Hvala", "answer_isv_cyr": "Хвала", "hint_ru": "Это слово начинается на 'Hv...' и используется во многих славянских языках Сверьтесь с таблицей теории: Zdrav budi!, Dobry denj!, Dobro jutro!, Dobry večer!, Do viděnja!, Prosim, Hvala, Da, Ne (Здравствуй!, Добрый день!, Доброе утро!, Добрый вечер!, До свидания!, Пожалуйста, Спасибо, Да, Нет).", "hint_en": "This word starts with 'Hv...' and is used in many Slavic languages  Check the lesson vocabulary: Zdrav budi!, Dobry denj!, Dobro jutro!, Dobry večer!, Do viděnja!, Prosim, Hvala, Da, Ne.", "xp": 20}]}$j$::jsonb) ON CONFLICT (id) DO UPDATE SET category_id = EXCLUDED.category_id, sort_order = EXCLUDED.sort_order, payload = EXCLUDED.payload;
INSERT INTO public.course_lessons (id, category_id, sort_order, payload) VALUES ('lesson_basics_1', 'cat_basics', 0, $j${"id": "lesson_basics_1", "category_id": "cat_basics", "title_ru": "Основные слова и фразы", "title_en": "Basic Words & Phrases", "order": 0, "theory": {"title_ru": "Введение в межславянский", "title_en": "Introduction to Interslavic", "blocks": [{"type": "text", "content_ru": "Межславянский (Medžuslovjansky) — это конструированный язык, предназначенный для общения между носителями разных славянских языков. Он основан на общих корнях и грамматических формах славянских языков.", "content_en": "Interslavic (Medžuslovjansky) is a constructed language designed for communication between speakers of different Slavic languages. It is based on common roots and grammatical forms of Slavic languages."}, {"type": "text", "content_ru": "Межславянский можно писать как латиницей, так и кириллицей. В этом приложении вы можете переключаться между ними в любой момент.", "content_en": "Interslavic can be written in both Latin and Cyrillic scripts. In this app, you can switch between them at any time."}, {"type": "vocabulary_table", "items": [{"isv_lat": "ja", "isv_cyr": "ја", "ru": "я", "en": "I"}, {"isv_lat": "ty", "isv_cyr": "ты", "ru": "ты", "en": "you (sg.)"}, {"isv_lat": "on/ona/ono", "isv_cyr": "он/она/оно", "ru": "он/она/оно", "en": "he/she/it"}, {"isv_lat": "my", "isv_cyr": "мы", "ru": "мы", "en": "we"}, {"isv_lat": "vy", "isv_cyr": "вы", "ru": "вы", "en": "you (pl.)"}, {"isv_lat": "oni", "isv_cyr": "они", "ru": "они", "en": "they"}, {"isv_lat": "jest", "isv_cyr": "јест", "ru": "есть (быть)", "en": "is"}, {"isv_lat": "imati", "isv_cyr": "имати", "ru": "иметь", "en": "to have"}, {"isv_lat": "htěti", "isv_cyr": "хтєти", "ru": "хотеть", "en": "to want"}, {"isv_lat": "mogti", "isv_cyr": "могти", "ru": "мочь", "en": "can"}]}, {"type": "tip", "content_ru": "Межславянский — не один конкретный славянский язык. Он объединяет элементы из разных славянских языков, поэтому носители русского, польского, чешского и других языков легко его понимают.", "content_en": "Interslavic is not one specific Slavic language. It combines elements from different Slavic languages, making it easily understood by speakers of Russian, Polish, Czech, and other languages."}]}, "exercises": [{"type": "word_match", "instruction_ru": "Соедините местоимения с переводом", "instruction_en": "Match pronouns with their translation", "pairs": [{"isv_lat": "ja", "isv_cyr": "ја", "ru": "я", "en": "I"}, {"isv_lat": "ty", "isv_cyr": "ты", "ru": "ты", "en": "you"}, {"isv_lat": "my", "isv_cyr": "мы", "ru": "мы", "en": "we"}, {"isv_lat": "oni", "isv_cyr": "они", "ru": "они", "en": "they"}], "hint_ru": "Эти местоимения очень похожи на русские Сверьтесь с таблицей теории: ja, ty, on/ona/ono, my, vy, oni, jest, imati, htěti, mogti (я, ты, он/она/оно, мы, вы, они, есть (быть), иметь, хотеть, мочь).", "hint_en": "These pronouns are very similar to Russian  Check the lesson vocabulary: ja, ty, on/ona/ono, my, vy, oni, jest, imati, htěti, mogti.", "xp": 10}, {"type": "multiple_choice", "instruction_ru": "Что означает 'imati'?", "instruction_en": "What does 'imati' mean?", "question_isv_lat": "imati", "question_isv_cyr": "имати", "options_ru": ["иметь", "хотеть", "мочь", "быть"], "options_en": ["to have", "to want", "can", "to be"], "correct_index": 0, "hint_ru": "Подумайте о русском слове 'иметь' Сверьтесь с таблицей теории: ja, ty, on/ona/ono, my, vy, oni, jest, imati, htěti, mogti (я, ты, он/она/оно, мы, вы, они, есть (быть), иметь, хотеть, мочь).", "hint_en": "Think about the word 'иметь' (to have) in Russian  Check the lesson vocabulary: ja, ty, on/ona/ono, my, vy, oni, jest, imati, htěti, mogti.", "xp": 10}, {"type": "fill_blank", "instruction_ru": "Заполните пропуск", "instruction_en": "Fill in the blank", "sentence_isv_lat": "___ jest student.", "sentence_isv_cyr": "___ јест студент.", "answer_isv_lat": "On", "answer_isv_cyr": "Он", "translation_ru": "Он — студент.", "translation_en": "He is a student.", "hint_ru": "Местоимение 'он' в межславянском похоже на русское Сверьтесь с таблицей теории: ja, ty, on/ona/ono, my, vy, oni, jest, imati, htěti, mogti (я, ты, он/она/оно, мы, вы, они, есть (быть), иметь, хотеть, мочь).", "hint_en": "The pronoun 'he' in Interslavic is similar to Russian  Check the lesson vocabulary: ja, ty, on/ona/ono, my, vy, oni, jest, imati, htěti, mogti.", "xp": 15}, {"type": "text_input", "instruction_ru": "Напишите местоимение 'мы' на межславянском", "instruction_en": "Write the pronoun 'we' in Interslavic", "prompt_ru": "мы", "prompt_en": "we", "answer_isv_lat": "my", "answer_isv_cyr": "мы", "hint_ru": "Это слово идентично русскому Сверьтесь с таблицей теории: ja, ty, on/ona/ono, my, vy, oni, jest, imati, htěti, mogti (я, ты, он/она/оно, мы, вы, они, есть (быть), иметь, хотеть, мочь).", "hint_en": "This word is identical to Russian  Check the lesson vocabulary: ja, ty, on/ona/ono, my, vy, oni, jest, imati, htěti, mogti.", "xp": 20}]}$j$::jsonb) ON CONFLICT (id) DO UPDATE SET category_id = EXCLUDED.category_id, sort_order = EXCLUDED.sort_order, payload = EXCLUDED.payload;
INSERT INTO public.course_lessons (id, category_id, sort_order, payload) VALUES ('lesson_food_1', 'cat_food', 0, $j${"id": "lesson_food_1", "category_id": "cat_food", "title_ru": "Еда и напитки", "title_en": "Food & Drinks", "order": 0, "theory": {"title_ru": "Еда и напитки в межславянском", "title_en": "Food & Drinks in Interslavic", "blocks": [{"type": "text", "content_ru": "Названия многих продуктов питания в межславянском языке очень похожи на слова в других славянских языках. Это одна из самых простых тем для изучения!", "content_en": "Many food names in Interslavic are very similar to words in other Slavic languages. This is one of the easiest topics to learn!"}, {"type": "vocabulary_table", "items": [{"isv_lat": "hléb", "isv_cyr": "хлєб", "ru": "хлеб", "en": "bread"}, {"isv_lat": "voda", "isv_cyr": "вода", "ru": "вода", "en": "water"}, {"isv_lat": "mléko", "isv_cyr": "млєко", "ru": "молоко", "en": "milk"}, {"isv_lat": "meso", "isv_cyr": "месо", "ru": "мясо", "en": "meat"}, {"isv_lat": "ryba", "isv_cyr": "рыба", "ru": "рыба", "en": "fish"}, {"isv_lat": "jablko", "isv_cyr": "јаблко", "ru": "яблоко", "en": "apple"}, {"isv_lat": "čaj", "isv_cyr": "чај", "ru": "чай", "en": "tea"}, {"isv_lat": "kava", "isv_cyr": "кава", "ru": "кофе", "en": "coffee"}, {"isv_lat": "sol", "isv_cyr": "сол", "ru": "соль", "en": "salt"}, {"isv_lat": "sahar", "isv_cyr": "сахар", "ru": "сахар", "en": "sugar"}]}]}, "exercises": [{"type": "word_match", "instruction_ru": "Соедините продукты с переводом", "instruction_en": "Match food items with their translation", "pairs": [{"isv_lat": "hléb", "isv_cyr": "хлєб", "ru": "хлеб", "en": "bread"}, {"isv_lat": "voda", "isv_cyr": "вода", "ru": "вода", "en": "water"}, {"isv_lat": "mléko", "isv_cyr": "млєко", "ru": "молоко", "en": "milk"}, {"isv_lat": "ryba", "isv_cyr": "рыба", "ru": "рыба", "en": "fish"}], "hint_ru": "Все эти слова похожи на русские Сверьтесь с таблицей теории: hléb, voda, mléko, meso, ryba, jablko, čaj, kava, sol, sahar (хлеб, вода, молоко, мясо, рыба, яблоко, чай, кофе, соль, сахар).", "hint_en": "All these words are similar to Russian  Check the lesson vocabulary: hléb, voda, mléko, meso, ryba, jablko, čaj, kava, sol, sahar.", "xp": 10}, {"type": "multiple_choice", "instruction_ru": "Переведите слово", "instruction_en": "Translate the word", "question_isv_lat": "čaj", "question_isv_cyr": "чај", "options_ru": ["чай", "кофе", "вода", "молоко"], "options_en": ["tea", "coffee", "water", "milk"], "correct_index": 0, "hint_ru": "Это горячий напиток, который пьют из чашки Сверьтесь с таблицей теории: hléb, voda, mléko, meso, ryba, jablko, čaj, kava, sol, sahar (хлеб, вода, молоко, мясо, рыба, яблоко, чай, кофе, соль, сахар).", "hint_en": "This is a hot drink served in a cup  Check the lesson vocabulary: hléb, voda, mléko, meso, ryba, jablko, čaj, kava, sol, sahar.", "xp": 10}, {"type": "fill_blank", "instruction_ru": "Заполните пропуск", "instruction_en": "Fill in the blank", "sentence_isv_lat": "Ja pijem ___.", "sentence_isv_cyr": "Ја пијем ___.", "answer_isv_lat": "vodu", "answer_isv_cyr": "воду", "translation_ru": "Я пью воду.", "translation_en": "I drink water.", "hint_ru": "Слово 'вода' в винительном падеже Сверьтесь с таблицей теории: hléb, voda, mléko, meso, ryba, jablko, čaj, kava, sol, sahar (хлеб, вода, молоко, мясо, рыба, яблоко, чай, кофе, соль, сахар).", "hint_en": "The word 'water' in accusative case  Check the lesson vocabulary: hléb, voda, mléko, meso, ryba, jablko, čaj, kava, sol, sahar.", "xp": 15}, {"type": "text_input", "instruction_ru": "Напишите 'хлеб' на межславянском", "instruction_en": "Write 'bread' in Interslavic", "prompt_ru": "хлеб", "prompt_en": "bread", "answer_isv_lat": "hléb", "answer_isv_cyr": "хлєб", "hint_ru": "Очень похоже на русское слово, но пишется немного иначе Сверьтесь с таблицей теории: hléb, voda, mléko, meso, ryba, jablko, čaj, kava, sol, sahar (хлеб, вода, молоко, мясо, рыба, яблоко, чай, кофе, соль, сахар).", "hint_en": "Very similar to the Russian word, but spelled slightly differently  Check the lesson vocabulary: hléb, voda, mléko, meso, ryba, jablko, čaj, kava, sol, sahar.", "xp": 20}]}$j$::jsonb) ON CONFLICT (id) DO UPDATE SET category_id = EXCLUDED.category_id, sort_order = EXCLUDED.sort_order, payload = EXCLUDED.payload;
INSERT INTO public.course_lessons (id, category_id, sort_order, payload) VALUES ('lesson_family_1', 'cat_family', 0, $j${"id": "lesson_family_1", "category_id": "cat_family", "title_ru": "Семья", "title_en": "Family", "order": 0, "theory": {"title_ru": "Семья в межславянском", "title_en": "Family in Interslavic", "blocks": [{"type": "text", "content_ru": "Слова, связанные с семьёй, являются одними из самых древних и общих для всех славянских языков. Межславянские слова очень близки к их русским эквивалентам.", "content_en": "Family-related words are among the oldest and most common across all Slavic languages. Interslavic words are very close to their Russian equivalents."}, {"type": "vocabulary_table", "items": [{"isv_lat": "otec", "isv_cyr": "отец", "ru": "отец", "en": "father"}, {"isv_lat": "mati", "isv_cyr": "мати", "ru": "мать", "en": "mother"}, {"isv_lat": "syn", "isv_cyr": "сын", "ru": "сын", "en": "son"}, {"isv_lat": "dčer", "isv_cyr": "дчер", "ru": "дочь", "en": "daughter"}, {"isv_lat": "brat", "isv_cyr": "брат", "ru": "брат", "en": "brother"}, {"isv_lat": "sestra", "isv_cyr": "сестра", "ru": "сестра", "en": "sister"}, {"isv_lat": "ded", "isv_cyr": "дед", "ru": "дедушка", "en": "grandfather"}, {"isv_lat": "baba", "isv_cyr": "баба", "ru": "бабушка", "en": "grandmother"}, {"isv_lat": "muž", "isv_cyr": "муж", "ru": "муж", "en": "husband"}, {"isv_lat": "žena", "isv_cyr": "жена", "ru": "жена", "en": "wife"}]}]}, "exercises": [{"type": "word_match", "instruction_ru": "Соедините слова с переводом", "instruction_en": "Match words with their translation", "pairs": [{"isv_lat": "otec", "isv_cyr": "отец", "ru": "отец", "en": "father"}, {"isv_lat": "mati", "isv_cyr": "мати", "ru": "мать", "en": "mother"}, {"isv_lat": "brat", "isv_cyr": "брат", "ru": "брат", "en": "brother"}, {"isv_lat": "sestra", "isv_cyr": "сестра", "ru": "сестра", "en": "sister"}], "hint_ru": "Семейные слова почти одинаковы в русском и межславянском Сверьтесь с таблицей теории: otec, mati, syn, dčer, brat, sestra, ded, baba, muž, žena (отец, мать, сын, дочь, брат, сестра, дедушка, бабушка, муж, жена).", "hint_en": "Family words are almost identical in Russian and Interslavic  Check the lesson vocabulary: otec, mati, syn, dčer, brat, sestra, ded, baba, muž, žena.", "xp": 10}, {"type": "multiple_choice", "instruction_ru": "Кто такой 'syn'?", "instruction_en": "Who is 'syn'?", "question_isv_lat": "syn", "question_isv_cyr": "сын", "options_ru": ["сын", "дочь", "брат", "муж"], "options_en": ["son", "daughter", "brother", "husband"], "correct_index": 0, "hint_ru": "Это слово идентично русскому Сверьтесь с таблицей теории: otec, mati, syn, dčer, brat, sestra, ded, baba, muž, žena (отец, мать, сын, дочь, брат, сестра, дедушка, бабушка, муж, жена).", "hint_en": "This word is identical to Russian  Check the lesson vocabulary: otec, mati, syn, dčer, brat, sestra, ded, baba, muž, žena.", "xp": 10}, {"type": "fill_blank", "instruction_ru": "Заполните пропуск", "instruction_en": "Fill in the blank", "sentence_isv_lat": "Moja ___ jest učiteljka.", "sentence_isv_cyr": "Моја ___ јест учитељка.", "answer_isv_lat": "sestra", "answer_isv_cyr": "сестра", "translation_ru": "Моя сестра — учительница.", "translation_en": "My sister is a teacher.", "hint_ru": "Женский родственник, дочь тех же родителей Сверьтесь с таблицей теории: otec, mati, syn, dčer, brat, sestra, ded, baba, muž, žena (отец, мать, сын, дочь, брат, сестра, дедушка, бабушка, муж, жена).", "hint_en": "A female relative, a daughter of the same parents  Check the lesson vocabulary: otec, mati, syn, dčer, brat, sestra, ded, baba, muž, žena.", "xp": 15}, {"type": "text_input", "instruction_ru": "Напишите 'брат' на межславянском", "instruction_en": "Write 'brother' in Interslavic", "prompt_ru": "брат", "prompt_en": "brother", "answer_isv_lat": "brat", "answer_isv_cyr": "брат", "hint_ru": "Слово идентично русскому Сверьтесь с таблицей теории: otec, mati, syn, dčer, brat, sestra, ded, baba, muž, žena (отец, мать, сын, дочь, брат, сестра, дедушка, бабушка, муж, жена).", "hint_en": "The word is identical to Russian  Check the lesson vocabulary: otec, mati, syn, dčer, brat, sestra, ded, baba, muž, žena.", "xp": 20}]}$j$::jsonb) ON CONFLICT (id) DO UPDATE SET category_id = EXCLUDED.category_id, sort_order = EXCLUDED.sort_order, payload = EXCLUDED.payload;
INSERT INTO public.course_lessons (id, category_id, sort_order, payload) VALUES ('lesson_numbers_1', 'cat_numbers', 0, $j${"id": "lesson_numbers_1", "category_id": "cat_numbers", "title_ru": "Числа 1-10", "title_en": "Numbers 1-10", "order": 0, "theory": {"title_ru": "Числительные в межславянском", "title_en": "Numerals in Interslavic", "blocks": [{"type": "text", "content_ru": "Числа в межславянском языке основаны на общеславянских корнях. Если вы знаете числа на любом славянском языке, вы быстро запомните их на межславянском.", "content_en": "Numbers in Interslavic are based on common Slavic roots. If you know numbers in any Slavic language, you'll quickly memorize them in Interslavic."}, {"type": "vocabulary_table", "items": [{"isv_lat": "jedin", "isv_cyr": "једин", "ru": "один", "en": "one"}, {"isv_lat": "dva", "isv_cyr": "два", "ru": "два", "en": "two"}, {"isv_lat": "tri", "isv_cyr": "три", "ru": "три", "en": "three"}, {"isv_lat": "četyri", "isv_cyr": "четыри", "ru": "четыре", "en": "four"}, {"isv_lat": "pet", "isv_cyr": "пет", "ru": "пять", "en": "five"}, {"isv_lat": "šest", "isv_cyr": "шест", "ru": "шесть", "en": "six"}, {"isv_lat": "sedm", "isv_cyr": "седм", "ru": "семь", "en": "seven"}, {"isv_lat": "osm", "isv_cyr": "осм", "ru": "восемь", "en": "eight"}, {"isv_lat": "devet", "isv_cyr": "девет", "ru": "девять", "en": "nine"}, {"isv_lat": "deset", "isv_cyr": "десет", "ru": "десять", "en": "ten"}]}]}, "exercises": [{"type": "word_match", "instruction_ru": "Соедините числа с переводом", "instruction_en": "Match numbers with their translation", "pairs": [{"isv_lat": "jedin", "isv_cyr": "једин", "ru": "один", "en": "one"}, {"isv_lat": "tri", "isv_cyr": "три", "ru": "три", "en": "three"}, {"isv_lat": "pet", "isv_cyr": "пет", "ru": "пять", "en": "five"}, {"isv_lat": "deset", "isv_cyr": "десет", "ru": "десять", "en": "ten"}], "hint_ru": "Сравните с русскими числительными Сверьтесь с таблицей теории: jedin, dva, tri, četyri, pet, šest, sedm, osm, devet, deset (один, два, три, четыре, пять, шесть, семь, восемь, девять, десять).", "hint_en": "Compare with Russian numerals  Check the lesson vocabulary: jedin, dva, tri, četyri, pet, šest, sedm, osm, devet, deset.", "xp": 10}, {"type": "multiple_choice", "instruction_ru": "Какое это число?", "instruction_en": "What number is this?", "question_isv_lat": "sedm", "question_isv_cyr": "седм", "options_ru": ["семь", "шесть", "восемь", "девять"], "options_en": ["seven", "six", "eight", "nine"], "correct_index": 0, "hint_ru": "Сравните с русским 'семь' Сверьтесь с таблицей теории: jedin, dva, tri, četyri, pet, šest, sedm, osm, devet, deset (один, два, три, четыре, пять, шесть, семь, восемь, девять, десять).", "hint_en": "Compare with Russian 'sem' (seven)  Check the lesson vocabulary: jedin, dva, tri, četyri, pet, šest, sedm, osm, devet, deset.", "xp": 10}, {"type": "fill_blank", "instruction_ru": "Заполните пропуск", "instruction_en": "Fill in the blank", "sentence_isv_lat": "Ja imam ___ bratov.", "sentence_isv_cyr": "Ја имам ___ братов.", "answer_isv_lat": "dva", "answer_isv_cyr": "два", "translation_ru": "У меня два брата.", "translation_en": "I have two brothers.", "hint_ru": "Число 2 — одинаково почти во всех славянских языках Сверьтесь с таблицей теории: jedin, dva, tri, četyri, pet, šest, sedm, osm, devet, deset (один, два, три, четыре, пять, шесть, семь, восемь, девять, десять).", "hint_en": "Number 2 — almost the same in all Slavic languages  Check the lesson vocabulary: jedin, dva, tri, četyri, pet, šest, sedm, osm, devet, deset.", "xp": 15}, {"type": "text_input", "instruction_ru": "Напишите число 'четыре' на межславянском", "instruction_en": "Write the number 'four' in Interslavic", "prompt_ru": "четыре", "prompt_en": "four", "answer_isv_lat": "četyri", "answer_isv_cyr": "четыри", "hint_ru": "Очень похоже на русское 'четыре' Сверьтесь с таблицей теории: jedin, dva, tri, četyri, pet, šest, sedm, osm, devet, deset (один, два, три, четыре, пять, шесть, семь, восемь, девять, десять).", "hint_en": "Very similar to Russian 'chetyre'  Check the lesson vocabulary: jedin, dva, tri, četyri, pet, šest, sedm, osm, devet, deset.", "xp": 20}]}$j$::jsonb) ON CONFLICT (id) DO UPDATE SET category_id = EXCLUDED.category_id, sort_order = EXCLUDED.sort_order, payload = EXCLUDED.payload;
INSERT INTO public.course_lessons (id, category_id, sort_order, payload) VALUES ('lesson_colors_1', 'cat_colors', 0, $j${"id": "lesson_colors_1", "category_id": "cat_colors", "title_ru": "Цвета", "title_en": "Colors", "order": 0, "theory": {"title_ru": "Цвета в межславянском", "title_en": "Colors in Interslavic", "blocks": [{"type": "text", "content_ru": "Цвета — важная часть базового словарного запаса. Многие названия цветов в межславянском языке имеют общеславянские корни.", "content_en": "Colors are an important part of basic vocabulary. Many color names in Interslavic have common Slavic roots."}, {"type": "vocabulary_table", "items": [{"isv_lat": "črveny", "isv_cyr": "чрвены", "ru": "красный", "en": "red"}, {"isv_lat": "siny", "isv_cyr": "сины", "ru": "синий", "en": "blue"}, {"isv_lat": "zeleny", "isv_cyr": "зелены", "ru": "зелёный", "en": "green"}, {"isv_lat": "žŭlty", "isv_cyr": "жŭлты", "ru": "жёлтый", "en": "yellow"}, {"isv_lat": "běly", "isv_cyr": "бєлы", "ru": "белый", "en": "white"}, {"isv_lat": "čŕny", "isv_cyr": "чрны", "ru": "чёрный", "en": "black"}]}]}, "exercises": [{"type": "word_match", "instruction_ru": "Соедините цвета с переводом", "instruction_en": "Match colors with their translation", "pairs": [{"isv_lat": "črveny", "isv_cyr": "чрвены", "ru": "красный", "en": "red"}, {"isv_lat": "siny", "isv_cyr": "сины", "ru": "синий", "en": "blue"}, {"isv_lat": "zeleny", "isv_cyr": "зелены", "ru": "зелёный", "en": "green"}, {"isv_lat": "běly", "isv_cyr": "бєлы", "ru": "белый", "en": "white"}], "hint_ru": "Корни этих слов общие для многих славянских языков Сверьтесь с таблицей теории: črveny, siny, zeleny, žŭlty, běly, čŕny (красный, синий, зелёный, жёлтый, белый, чёрный).", "hint_en": "The roots of these words are common to many Slavic languages  Check the lesson vocabulary: črveny, siny, zeleny, žŭlty, běly, čŕny.", "xp": 10}, {"type": "multiple_choice", "instruction_ru": "Какой это цвет?", "instruction_en": "What color is this?", "question_isv_lat": "zeleny", "question_isv_cyr": "зелены", "options_ru": ["зелёный", "синий", "красный", "жёлтый"], "options_en": ["green", "blue", "red", "yellow"], "correct_index": 0, "hint_ru": "Сравните с русским 'зелёный' Сверьтесь с таблицей теории: črveny, siny, zeleny, žŭlty, běly, čŕny (красный, синий, зелёный, жёлтый, белый, чёрный).", "hint_en": "Compare with Russian 'zelyony'  Check the lesson vocabulary: črveny, siny, zeleny, žŭlty, běly, čŕny.", "xp": 10}, {"type": "fill_blank", "instruction_ru": "Заполните пропуск", "instruction_en": "Fill in the blank", "sentence_isv_lat": "___ kot spi na divanu.", "sentence_isv_cyr": "___ кот спи на дивану.", "answer_isv_lat": "Čŕny", "answer_isv_cyr": "Чрны", "translation_ru": "Чёрный кот спит на диване.", "translation_en": "A black cat sleeps on the sofa.", "hint_ru": "Этот цвет ассоциируется с ночью и тьмой Сверьтесь с таблицей теории: črveny, siny, zeleny, žŭlty, běly, čŕny (красный, синий, зелёный, жёлтый, белый, чёрный).", "hint_en": "This color is associated with night and darkness  Check the lesson vocabulary: črveny, siny, zeleny, žŭlty, běly, čŕny.", "xp": 15}, {"type": "text_input", "instruction_ru": "Напишите 'белый' на межславянском", "instruction_en": "Write 'white' in Interslavic", "prompt_ru": "белый", "prompt_en": "white", "answer_isv_lat": "běly", "answer_isv_cyr": "бєлы", "hint_ru": "Похоже на русское 'белый', но с другой гласной Сверьтесь с таблицей теории: črveny, siny, zeleny, žŭlty, běly, čŕny (красный, синий, зелёный, жёлтый, белый, чёрный).", "hint_en": "Similar to Russian 'bely', but with a different vowel  Check the lesson vocabulary: črveny, siny, zeleny, žŭlty, běly, čŕny.", "xp": 20}]}$j$::jsonb) ON CONFLICT (id) DO UPDATE SET category_id = EXCLUDED.category_id, sort_order = EXCLUDED.sort_order, payload = EXCLUDED.payload;
INSERT INTO public.course_lessons (id, category_id, sort_order, payload) VALUES ('lesson_travel_1', 'cat_travel', 0, $j${"id": "lesson_travel_1", "category_id": "cat_travel", "title_ru": "Путешествия", "title_en": "Travel", "order": 0, "theory": {"title_ru": "Путешествия и транспорт", "title_en": "Travel & Transport", "blocks": [{"type": "text", "content_ru": "Путешествуя по славянским странам, знание межславянского языка может быть очень полезным. Вот основные слова и фразы для путешествий.", "content_en": "When traveling through Slavic countries, knowledge of Interslavic can be very useful. Here are basic travel words and phrases."}, {"type": "vocabulary_table", "items": [{"isv_lat": "vlak", "isv_cyr": "влак", "ru": "поезд", "en": "train"}, {"isv_lat": "avtobus", "isv_cyr": "автобус", "ru": "автобус", "en": "bus"}, {"isv_lat": "letišče", "isv_cyr": "летишче", "ru": "аэропорт", "en": "airport"}, {"isv_lat": "hotel", "isv_cyr": "хотел", "ru": "гостиница", "en": "hotel"}, {"isv_lat": "bilet", "isv_cyr": "билет", "ru": "билет", "en": "ticket"}, {"isv_lat": "mapa", "isv_cyr": "мапа", "ru": "карта", "en": "map"}, {"isv_lat": "ulica", "isv_cyr": "улица", "ru": "улица", "en": "street"}, {"isv_lat": "město", "isv_cyr": "мєсто", "ru": "город", "en": "city"}]}]}, "exercises": [{"type": "word_match", "instruction_ru": "Соедините слова с переводом", "instruction_en": "Match words with their translation", "pairs": [{"isv_lat": "vlak", "isv_cyr": "влак", "ru": "поезд", "en": "train"}, {"isv_lat": "bilet", "isv_cyr": "билет", "ru": "билет", "en": "ticket"}, {"isv_lat": "ulica", "isv_cyr": "улица", "ru": "улица", "en": "street"}, {"isv_lat": "město", "isv_cyr": "мєсто", "ru": "город", "en": "city"}], "hint_ru": "Некоторые из этих слов совпадают с русскими Сверьтесь с таблицей теории: vlak, avtobus, letišče, hotel, bilet, mapa, ulica, město (поезд, автобус, аэропорт, гостиница, билет, карта, улица, город).", "hint_en": "Some of these words are identical to Russian  Check the lesson vocabulary: vlak, avtobus, letišče, hotel, bilet, mapa, ulica, město.", "xp": 10}, {"type": "multiple_choice", "instruction_ru": "Что означает 'letišče'?", "instruction_en": "What does 'letišče' mean?", "question_isv_lat": "letišče", "question_isv_cyr": "летишче", "options_ru": ["аэропорт", "вокзал", "гостиница", "ресторан"], "options_en": ["airport", "station", "hotel", "restaurant"], "correct_index": 0, "hint_ru": "Корень слова связан с 'летать' Сверьтесь с таблицей теории: vlak, avtobus, letišče, hotel, bilet, mapa, ulica, město (поезд, автобус, аэропорт, гостиница, билет, карта, улица, город).", "hint_en": "The root of the word is related to 'flying'  Check the lesson vocabulary: vlak, avtobus, letišče, hotel, bilet, mapa, ulica, město.", "xp": 10}, {"type": "fill_blank", "instruction_ru": "Заполните пропуск", "instruction_en": "Fill in the blank", "sentence_isv_lat": "Gdě jest ___?", "sentence_isv_cyr": "Гдє јест ___?", "answer_isv_lat": "hotel", "answer_isv_cyr": "хотел", "translation_ru": "Где находится гостиница?", "translation_en": "Where is the hotel?", "hint_ru": "Место, где останавливаются путешественники Сверьтесь с таблицей теории: vlak, avtobus, letišče, hotel, bilet, mapa, ulica, město (поезд, автобус, аэропорт, гостиница, билет, карта, улица, город).", "hint_en": "A place where travelers stay  Check the lesson vocabulary: vlak, avtobus, letišče, hotel, bilet, mapa, ulica, město.", "xp": 15}, {"type": "text_input", "instruction_ru": "Напишите 'билет' на межславянском", "instruction_en": "Write 'ticket' in Interslavic", "prompt_ru": "билет", "prompt_en": "ticket", "answer_isv_lat": "bilet", "answer_isv_cyr": "билет", "hint_ru": "Слово идентично русскому Сверьтесь с таблицей теории: vlak, avtobus, letišče, hotel, bilet, mapa, ulica, město (поезд, автобус, аэропорт, гостиница, билет, карта, улица, город).", "hint_en": "The word is identical to Russian  Check the lesson vocabulary: vlak, avtobus, letišče, hotel, bilet, mapa, ulica, město.", "xp": 20}]}$j$::jsonb) ON CONFLICT (id) DO UPDATE SET category_id = EXCLUDED.category_id, sort_order = EXCLUDED.sort_order, payload = EXCLUDED.payload;
INSERT INTO public.course_lessons (id, category_id, sort_order, payload) VALUES ('lesson_nouns_1', 'cat_nouns', 0, $j${"id": "lesson_nouns_1", "category_id": "cat_nouns", "title_ru": "Существительные: Основы", "title_en": "Nouns: Basics", "order": 0, "theory": {"title_ru": "Существительные в межславянском", "title_en": "Nouns in Interslavic", "blocks": [{"type": "text", "content_ru": "Like most Slavic languages, nouns in Interslavic have three grammatical genders (masculine, feminine, neuter), two numbers (singular, plural) and seven cases (nominative, accusative, genitive, dative, instrumental, locative, vocative). The vocative, used for addressing a person or object directly, is actually not a real case, as it behaves significantly different from other cases: it exists only in the singular of masculine and feminine nouns, it never affects adjectives or pronouns, and it has nothing to do with the syntactic structure of the sentence.", "content_en": "Like most Slavic languages, nouns in Interslavic have three grammatical genders (masculine, feminine, neuter), two numbers (singular, plural) and seven cases (nominative, accusative, genitive, dative, instrumental, locative, vocative). The vocative, used for addressing a person or object directly, is actually not a real case, as it behaves significantly different from other cases: it exists only in the singular of masculine and feminine nouns, it never affects adjectives or pronouns, and it has nothing to do with the syntactic structure of the sentence."}, {"type": "text", "content_ru": "Long and complicated paradigms are to be avoided, but we cannot escape distinguishing between a few different word classes. Basically, Interslavic has three declensions:", "content_en": "Long and complicated paradigms are to be avoided, but we cannot escape distinguishing between a few different word classes. Basically, Interslavic has three declensions:"}, {"type": "text", "content_ru": "Within the first declension, we distinguish between three types. This difference affects only the nominative, the accusative and the vocative:", "content_en": "Within the first declension, we distinguish between three types. This difference affects only the nominative, the accusative and the vocative:"}, {"type": "text", "content_ru": "Another distinction is made between hard and soft declension patterns. Soft stems are stems ending inš,ž,č,c,j,ljornj. As a rule, after a soft stem the-oand-yof the ending become-e, the-ěbecomes-i.", "content_en": "Another distinction is made between hard and soft declension patterns. Soft stems are stems ending inš,ž,č,c,j,ljornj. As a rule, after a soft stem the-oand-yof the ending become-e, the-ěbecomes-i."}]}, "exercises": [{"type": "multiple_choice", "instruction_ru": "Сколько грамматических родов в межславянском?", "instruction_en": "How many grammatical genders are in Interslavic?", "question_isv_lat": "Koliko gramtičnyh rodov?", "question_isv_cyr": "Колико грамтичных родов?", "options_ru": ["3 (мужской, женский, средний)", "2 (мужской, женский)", "4", "1"], "options_en": ["3 (masculine, feminine, neuter)", "2 (masculine, feminine)", "4", "1"], "correct_index": 0, "hint_ru": "Как в русском языке", "hint_en": "Same as in Russian", "xp": 10}, {"type": "word_match", "instruction_ru": "Соедините существительные с их родом", "instruction_en": "Match nouns with their gender", "pairs": [{"isv_lat": "dom (m.)", "isv_cyr": "дом (м.)", "ru": "мужской род", "en": "masculine"}, {"isv_lat": "žena (f.)", "isv_cyr": "жена (ж.)", "ru": "женский род", "en": "feminine"}, {"isv_lat": "selo (n.)", "isv_cyr": "село (с.)", "ru": "средний род", "en": "neuter"}, {"isv_lat": "kosť (f.)", "isv_cyr": "кость (ж.)", "ru": "женский род (3 скл.)", "en": "feminine (3rd decl.)"}], "hint_ru": "Обратите внимание на окончания: согласный = м.р., -a = ж.р., -o/-e = с.р.", "hint_en": "Note the endings: consonant = masc., -a = fem., -o/-e = neut.", "xp": 15}, {"type": "fill_blank", "instruction_ru": "Заполните пропуск правильным окончанием", "instruction_en": "Fill in the correct ending", "sentence_isv_lat": "Ja vidžu dom___.", "sentence_isv_cyr": "Ја виджу дом___.", "answer_isv_lat": "", "answer_isv_cyr": "", "translation_ru": "Я вижу дом. (Винительный падеж неодушевл. = именительный)", "translation_en": "I see a house. (Accusative inanimate = nominative)", "hint_ru": "Для неодушевлённых мужского рода винительный = именительный", "hint_en": "For inanimate masculine nouns, accusative = nominative", "xp": 15}, {"type": "text_input", "instruction_ru": "Напишите множественное число слова 'brat'", "instruction_en": "Write the plural of 'brat'", "prompt_ru": "брат (мн.ч.)", "prompt_en": "brother (plural)", "answer_isv_lat": "brati", "answer_isv_cyr": "брати", "hint_ru": "Одушевлённые мужского рода во мн.ч. имеют окончание -i", "hint_en": "Animate masculine nouns in plural have the ending -i", "xp": 20}]}$j$::jsonb) ON CONFLICT (id) DO UPDATE SET category_id = EXCLUDED.category_id, sort_order = EXCLUDED.sort_order, payload = EXCLUDED.payload;
INSERT INTO public.course_lessons (id, category_id, sort_order, payload) VALUES ('lesson_verbs_1', 'cat_verbs', 0, $j${"id": "lesson_verbs_1", "category_id": "cat_verbs", "title_ru": "Глаголы: Основы", "title_en": "Verbs: Basics", "order": 0, "theory": {"title_ru": "Глаголы в межславянском", "title_en": "Verbs in Interslavic", "blocks": [{"type": "text", "content_ru": "Глаголы в межславянском языке спрягаются по лицам и числам. Система спряжения упрощена по сравнению с отдельными славянскими языками, но сохраняет все важные формы.", "content_en": "Verbs in Interslavic are conjugated by person and number. The conjugation system is simplified compared to individual Slavic languages, but retains all important forms."}, {"type": "vocabulary_table", "items": [{"isv_lat": "ja dělam", "isv_cyr": "ја дєлам", "ru": "я делаю", "en": "I do"}, {"isv_lat": "ty dělaš", "isv_cyr": "ты дєлаш", "ru": "ты делаешь", "en": "you do"}, {"isv_lat": "on děla", "isv_cyr": "он дєла", "ru": "он делает", "en": "he does"}, {"isv_lat": "my dělamo", "isv_cyr": "мы дєламо", "ru": "мы делаем", "en": "we do"}, {"isv_lat": "vy dělate", "isv_cyr": "вы дєлате", "ru": "вы делаете", "en": "you do (pl.)"}, {"isv_lat": "oni dělajut", "isv_cyr": "они дєлајут", "ru": "они делают", "en": "they do"}]}, {"type": "tip", "content_ru": "Окончания глаголов: -m (я), -š (ты), -Ø (он/она), -mo (мы), -te (вы), -jut (они). Эти окончания используются для большинства глаголов.", "content_en": "Verb endings: -m (I), -š (you), -Ø (he/she), -mo (we), -te (you pl.), -jut (they). These endings are used for most verbs."}]}, "exercises": [{"type": "word_match", "instruction_ru": "Соедините формы глагола с местоимениями", "instruction_en": "Match verb forms with pronouns", "pairs": [{"isv_lat": "dělam", "isv_cyr": "дєлам", "ru": "я (делаю)", "en": "I (do)"}, {"isv_lat": "dělaš", "isv_cyr": "дєлаш", "ru": "ты (делаешь)", "en": "you (do)"}, {"isv_lat": "dělamo", "isv_cyr": "дєламо", "ru": "мы (делаем)", "en": "we (do)"}, {"isv_lat": "dělajut", "isv_cyr": "дєлајут", "ru": "они (делают)", "en": "they (do)"}], "hint_ru": "Обратите внимание на окончания: -m, -š, -mo, -jut Сверьтесь с таблицей теории: ja dělam, ty dělaš, on děla, my dělamo, vy dělate, oni dělajut (я делаю, ты делаешь, он делает, мы делаем, вы делаете, они делают).", "hint_en": "Pay attention to endings: -m, -š, -mo, -jut  Check the lesson vocabulary: ja dělam, ty dělaš, on děla, my dělamo, vy dělate, oni dělajut.", "xp": 10}, {"type": "multiple_choice", "instruction_ru": "Выберите правильную форму", "instruction_en": "Choose the correct form", "question_isv_lat": "My ___ (dělati)", "question_isv_cyr": "Мы ___ (дєлати)", "options_ru": ["dělamo", "dělam", "dělaš", "dělajut"], "options_en": ["dělamo", "dělam", "dělaš", "dělajut"], "correct_index": 0, "hint_ru": "Для 'мы' используется окончание -mo Сверьтесь с таблицей теории: ja dělam, ty dělaš, on děla, my dělamo, vy dělate, oni dělajut (я делаю, ты делаешь, он делает, мы делаем, вы делаете, они делают).", "hint_en": "For 'we', the ending -mo is used  Check the lesson vocabulary: ja dělam, ty dělaš, on děla, my dělamo, vy dělate, oni dělajut.", "xp": 10}, {"type": "fill_blank", "instruction_ru": "Заполните пропуск", "instruction_en": "Fill in the blank", "sentence_isv_lat": "Oni ___ v školu.", "sentence_isv_cyr": "Они ___ в школу.", "answer_isv_lat": "idut", "answer_isv_cyr": "идут", "translation_ru": "Они идут в школу.", "translation_en": "They go to school.", "hint_ru": "Глагол 'идти' в 3-м лице мн.ч. Сверьтесь с таблицей теории: ja dělam, ty dělaš, on děla, my dělamo, vy dělate, oni dělajut (я делаю, ты делаешь, он делает, мы делаем, вы делаете, они делают).", "hint_en": "The verb 'to go' in 3rd person plural  Check the lesson vocabulary: ja dělam, ty dělaš, on děla, my dělamo, vy dělate, oni dělajut.", "xp": 15}, {"type": "text_input", "instruction_ru": "Проспрягайте 'znati' для 'ja'", "instruction_en": "Conjugate 'znati' for 'ja'", "prompt_ru": "я знаю", "prompt_en": "I know", "answer_isv_lat": "znam", "answer_isv_cyr": "знам", "hint_ru": "Окончание первого лица единственного числа: -m Сверьтесь с таблицей теории: ja dělam, ty dělaš, on děla, my dělamo, vy dělate, oni dělajut (я делаю, ты делаешь, он делает, мы делаем, вы делаете, они делают).", "hint_en": "First person singular ending: -m  Check the lesson vocabulary: ja dělam, ty dělaš, on děla, my dělamo, vy dělate, oni dělajut.", "xp": 20}]}$j$::jsonb) ON CONFLICT (id) DO UPDATE SET category_id = EXCLUDED.category_id, sort_order = EXCLUDED.sort_order, payload = EXCLUDED.payload;
INSERT INTO public.course_lessons (id, category_id, sort_order, payload) VALUES ('lesson_adjectives_1', 'cat_adjectives', 0, $j${"id": "lesson_adjectives_1", "category_id": "cat_adjectives", "title_ru": "Прилагательные: Основы", "title_en": "Adjectives: Basics", "order": 0, "theory": {"title_ru": "Прилагательные в межславянском", "title_en": "Adjectives in Interslavic", "blocks": [{"type": "text", "content_ru": "Прилагательные в межславянском языке согласуются с существительными в роде, числе и падеже. Основные окончания: мужской род -y, женский род -a, средний род -o.", "content_en": "Adjectives in Interslavic agree with nouns in gender, number, and case. Basic endings: masculine -y, feminine -a, neuter -o."}, {"type": "vocabulary_table", "items": [{"isv_lat": "dobry / dobra / dobro", "isv_cyr": "добры / добра / добро", "ru": "хороший/ая/ее", "en": "good (m/f/n)"}, {"isv_lat": "veliky / velika / veliko", "isv_cyr": "великы / велика / велико", "ru": "большой/ая/ое", "en": "big (m/f/n)"}, {"isv_lat": "maly / mala / malo", "isv_cyr": "малы / мала / мало", "ru": "маленький/ая/ое", "en": "small (m/f/n)"}, {"isv_lat": "novy / nova / novo", "isv_cyr": "новы / нова / ново", "ru": "новый/ая/ое", "en": "new (m/f/n)"}, {"isv_lat": "stary / stara / staro", "isv_cyr": "стары / стара / старо", "ru": "старый/ая/ое", "en": "old (m/f/n)"}]}]}, "exercises": [{"type": "word_match", "instruction_ru": "Соедините прилагательные с переводом", "instruction_en": "Match adjectives with their translation", "pairs": [{"isv_lat": "dobry", "isv_cyr": "добры", "ru": "хороший", "en": "good"}, {"isv_lat": "veliky", "isv_cyr": "великы", "ru": "большой", "en": "big"}, {"isv_lat": "maly", "isv_cyr": "малы", "ru": "маленький", "en": "small"}, {"isv_lat": "novy", "isv_cyr": "новы", "ru": "новый", "en": "new"}], "hint_ru": "Все слова имеют общеславянские корни Сверьтесь с таблицей теории: dobry / dobra / dobro, veliky / velika / veliko, maly / mala / malo, novy / nova / novo, stary / stara / staro (хороший/ая/ее, большой/ая/ое, маленький/ая/ое, новый/ая/ое, старый/ая/ое).", "hint_en": "All words have common Slavic roots  Check the lesson vocabulary: dobry / dobra / dobro, veliky / velika / veliko, maly / mala / malo, novy / nova / novo, stary / stara / staro.", "xp": 10}, {"type": "multiple_choice", "instruction_ru": "Выберите правильную форму", "instruction_en": "Choose the correct form", "question_isv_lat": "___  žena (dobry)", "question_isv_cyr": "___  жена (добры)", "options_ru": ["dobra", "dobry", "dobro", "dobre"], "options_en": ["dobra", "dobry", "dobro", "dobre"], "correct_index": 0, "hint_ru": "'žena' — женский род, значит окончание -a Сверьтесь с таблицей теории: dobry / dobra / dobro, veliky / velika / veliko, maly / mala / malo, novy / nova / novo, stary / stara / staro (хороший/ая/ее, большой/ая/ое, маленький/ая/ое, новый/ая/ое, старый/ая/ое).", "hint_en": "'žena' is feminine, so the ending is -a  Check the lesson vocabulary: dobry / dobra / dobro, veliky / velika / veliko, maly / mala / malo, novy / nova / novo, stary / stara / staro.", "xp": 10}, {"type": "fill_blank", "instruction_ru": "Заполните пропуск", "instruction_en": "Fill in the blank", "sentence_isv_lat": "___ město jest krasno.", "sentence_isv_cyr": "___ мєсто јест красно.", "answer_isv_lat": "Novo", "answer_isv_cyr": "Ново", "translation_ru": "Новый город красив.", "translation_en": "The new city is beautiful.", "hint_ru": "'město' — средний род, окончание прилагательного -o Сверьтесь с таблицей теории: dobry / dobra / dobro, veliky / velika / veliko, maly / mala / malo, novy / nova / novo, stary / stara / staro (хороший/ая/ее, большой/ая/ое, маленький/ая/ое, новый/ая/ое, старый/ая/ое).", "hint_en": "'město' is neuter, adjective ending is -o  Check the lesson vocabulary: dobry / dobra / dobro, veliky / velika / veliko, maly / mala / malo, novy / nova / novo, stary / stara / staro.", "xp": 15}, {"type": "text_input", "instruction_ru": "Напишите 'старый' в женском роде на межславянском", "instruction_en": "Write 'old' in feminine form in Interslavic", "prompt_ru": "старая", "prompt_en": "old (feminine)", "answer_isv_lat": "stara", "answer_isv_cyr": "стара", "hint_ru": "Мужской род 'stary', для женского замените -y на -a Сверьтесь с таблицей теории: dobry / dobra / dobro, veliky / velika / veliko, maly / mala / malo, novy / nova / novo, stary / stara / staro (хороший/ая/ее, большой/ая/ое, маленький/ая/ое, новый/ая/ое, старый/ая/ое).", "hint_en": "Masculine is 'stary', for feminine replace -y with -a  Check the lesson vocabulary: dobry / dobra / dobro, veliky / velika / veliko, maly / mala / malo, novy / nova / novo, stary / stara / staro.", "xp": 20}]}$j$::jsonb) ON CONFLICT (id) DO UPDATE SET category_id = EXCLUDED.category_id, sort_order = EXCLUDED.sort_order, payload = EXCLUDED.payload;
INSERT INTO public.course_lessons (id, category_id, sort_order, payload) VALUES ('lesson_pronouns_1', 'cat_pronouns', 0, $j${"id": "lesson_pronouns_1", "category_id": "cat_pronouns", "title_ru": "Местоимения", "title_en": "Pronouns", "order": 0, "theory": {"title_ru": "Местоимения в межславянском", "title_en": "Pronouns in Interslavic", "blocks": [{"type": "text", "content_ru": "Личные местоимения в межславянском языке очень похожи на русские. Они склоняются по падежам.", "content_en": "Personal pronouns in Interslavic are very similar to Russian. They decline by case."}, {"type": "vocabulary_table", "items": [{"isv_lat": "ja / mene / mně", "isv_cyr": "ја / мене / мнє", "ru": "я / меня / мне", "en": "I / me / to me"}, {"isv_lat": "ty / tebe / tobě", "isv_cyr": "ты / тебе / тобє", "ru": "ты / тебя / тебе", "en": "you / you / to you"}, {"isv_lat": "on / jego / jemu", "isv_cyr": "он / јего / јему", "ru": "он / его / ему", "en": "he / him / to him"}, {"isv_lat": "ona / jej / jej", "isv_cyr": "она / јеј / јеј", "ru": "она / её / ей", "en": "she / her / to her"}, {"isv_lat": "my / nas / nam", "isv_cyr": "мы / нас / нам", "ru": "мы / нас / нам", "en": "we / us / to us"}, {"isv_lat": "vy / vas / vam", "isv_cyr": "вы / вас / вам", "ru": "вы / вас / вам", "en": "you / you / to you"}]}]}, "exercises": [{"type": "word_match", "instruction_ru": "Соедините местоимения", "instruction_en": "Match pronouns", "pairs": [{"isv_lat": "mene", "isv_cyr": "мене", "ru": "меня", "en": "me"}, {"isv_lat": "tebe", "isv_cyr": "тебе", "ru": "тебя", "en": "you (acc.)"}, {"isv_lat": "nas", "isv_cyr": "нас", "ru": "нас", "en": "us"}, {"isv_lat": "vas", "isv_cyr": "вас", "ru": "вас", "en": "you (pl. acc.)"}], "hint_ru": "Формы очень близки к русским Сверьтесь с таблицей теории: ja / mene / mně, ty / tebe / tobě, on / jego / jemu, ona / jej / jej, my / nas / nam, vy / vas / vam (я / меня / мне, ты / тебя / тебе, он / его / ему, она / её / ей, мы / нас / нам, вы / вас / вам).", "hint_en": "Forms are very close to Russian  Check the lesson vocabulary: ja / mene / mně, ty / tebe / tobě, on / jego / jemu, ona / jej / jej, my / nas / nam, vy / vas / vam.", "xp": 10}, {"type": "multiple_choice", "instruction_ru": "Выберите правильный перевод", "instruction_en": "Choose the correct translation", "question_isv_lat": "jego", "question_isv_cyr": "јего", "options_ru": ["его", "её", "их", "нас"], "options_en": ["his/him", "her", "their", "us"], "correct_index": 0, "hint_ru": "Это родительный/винительный падеж местоимения 'on' Сверьтесь с таблицей теории: ja / mene / mně, ty / tebe / tobě, on / jego / jemu, ona / jej / jej, my / nas / nam, vy / vas / vam (я / меня / мне, ты / тебя / тебе, он / его / ему, она / её / ей, мы / нас / нам, вы / вас / вам).", "hint_en": "This is the genitive/accusative of the pronoun 'on'  Check the lesson vocabulary: ja / mene / mně, ty / tebe / tobě, on / jego / jemu, ona / jej / jej, my / nas / nam, vy / vas / vam.", "xp": 10}, {"type": "fill_blank", "instruction_ru": "Заполните пропуск", "instruction_en": "Fill in the blank", "sentence_isv_lat": "Ja vidžu ___.", "sentence_isv_cyr": "Ја виджу ___.", "answer_isv_lat": "tebe", "answer_isv_cyr": "тебе", "translation_ru": "Я вижу тебя.", "translation_en": "I see you.", "hint_ru": "Винительный падеж от 'ty' Сверьтесь с таблицей теории: ja / mene / mně, ty / tebe / tobě, on / jego / jemu, ona / jej / jej, my / nas / nam, vy / vas / vam (я / меня / мне, ты / тебя / тебе, он / его / ему, она / её / ей, мы / нас / нам, вы / вас / вам).", "hint_en": "Accusative case of 'ty'  Check the lesson vocabulary: ja / mene / mně, ty / tebe / tobě, on / jego / jemu, ona / jej / jej, my / nas / nam, vy / vas / vam.", "xp": 15}, {"type": "text_input", "instruction_ru": "Напишите дательный падеж от 'my'", "instruction_en": "Write the dative case of 'my'", "prompt_ru": "нам", "prompt_en": "to us", "answer_isv_lat": "nam", "answer_isv_cyr": "нам", "hint_ru": "Идентично русскому Сверьтесь с таблицей теории: ja / mene / mně, ty / tebe / tobě, on / jego / jemu, ona / jej / jej, my / nas / nam, vy / vas / vam (я / меня / мне, ты / тебя / тебе, он / его / ему, она / её / ей, мы / нас / нам, вы / вас / вам).", "hint_en": "Identical to Russian  Check the lesson vocabulary: ja / mene / mně, ty / tebe / tobě, on / jego / jemu, ona / jej / jej, my / nas / nam, vy / vas / vam.", "xp": 20}]}$j$::jsonb) ON CONFLICT (id) DO UPDATE SET category_id = EXCLUDED.category_id, sort_order = EXCLUDED.sort_order, payload = EXCLUDED.payload;
INSERT INTO public.course_lessons (id, category_id, sort_order, payload) VALUES ('lesson_prepositions_1', 'cat_prepositions', 0, $j${"id": "lesson_prepositions_1", "category_id": "cat_prepositions", "title_ru": "Предлоги", "title_en": "Prepositions", "order": 0, "theory": {"title_ru": "Предлоги в межславянском", "title_en": "Prepositions in Interslavic", "blocks": [{"type": "text", "content_ru": "Предлоги в межславянском языке управляют определёнными падежами, как и в других славянских языках. Многие предлоги идентичны русским.", "content_en": "Prepositions in Interslavic govern specific cases, as in other Slavic languages. Many prepositions are identical to Russian."}, {"type": "vocabulary_table", "items": [{"isv_lat": "v / vo", "isv_cyr": "в / во", "ru": "в", "en": "in"}, {"isv_lat": "na", "isv_cyr": "на", "ru": "на", "en": "on"}, {"isv_lat": "iz", "isv_cyr": "из", "ru": "из", "en": "from"}, {"isv_lat": "do", "isv_cyr": "до", "ru": "до", "en": "to/until"}, {"isv_lat": "s / so", "isv_cyr": "с / со", "ru": "с", "en": "with"}, {"isv_lat": "bez", "isv_cyr": "без", "ru": "без", "en": "without"}, {"isv_lat": "za", "isv_cyr": "за", "ru": "за", "en": "behind/for"}, {"isv_lat": "pri", "isv_cyr": "при", "ru": "при", "en": "at/by"}]}]}, "exercises": [{"type": "word_match", "instruction_ru": "Соедините предлоги с переводом", "instruction_en": "Match prepositions with their translation", "pairs": [{"isv_lat": "v", "isv_cyr": "в", "ru": "в", "en": "in"}, {"isv_lat": "na", "isv_cyr": "на", "ru": "на", "en": "on"}, {"isv_lat": "iz", "isv_cyr": "из", "ru": "из", "en": "from"}, {"isv_lat": "bez", "isv_cyr": "без", "ru": "без", "en": "without"}], "hint_ru": "Предлоги почти идентичны русским Сверьтесь с таблицей теории: v / vo, na, iz, do, s / so, bez, za, pri (в, на, из, до, с, без, за, при).", "hint_en": "Prepositions are almost identical to Russian  Check the lesson vocabulary: v / vo, na, iz, do, s / so, bez, za, pri.", "xp": 10}, {"type": "multiple_choice", "instruction_ru": "Что означает 'bez'?", "instruction_en": "What does 'bez' mean?", "question_isv_lat": "bez", "question_isv_cyr": "без", "options_ru": ["без", "с", "за", "на"], "options_en": ["without", "with", "behind", "on"], "correct_index": 0, "hint_ru": "Идентично русскому предлогу Сверьтесь с таблицей теории: v / vo, na, iz, do, s / so, bez, za, pri (в, на, из, до, с, без, за, при).", "hint_en": "Identical to the Russian preposition  Check the lesson vocabulary: v / vo, na, iz, do, s / so, bez, za, pri.", "xp": 10}, {"type": "fill_blank", "instruction_ru": "Заполните пропуск", "instruction_en": "Fill in the blank", "sentence_isv_lat": "Ja idem ___ školu.", "sentence_isv_cyr": "Ја идем ___ школу.", "answer_isv_lat": "v", "answer_isv_cyr": "в", "translation_ru": "Я иду в школу.", "translation_en": "I go to school.", "hint_ru": "Предлог направления, такой же как в русском Сверьтесь с таблицей теории: v / vo, na, iz, do, s / so, bez, za, pri (в, на, из, до, с, без, за, при).", "hint_en": "Directional preposition, same as in Russian  Check the lesson vocabulary: v / vo, na, iz, do, s / so, bez, za, pri.", "xp": 15}, {"type": "text_input", "instruction_ru": "Напишите предлог 'с' (совместность) на межславянском", "instruction_en": "Write the preposition 'with' in Interslavic", "prompt_ru": "с (совместность)", "prompt_en": "with", "answer_isv_lat": "s", "answer_isv_cyr": "с", "hint_ru": "Один символ, идентичный русскому Сверьтесь с таблицей теории: v / vo, na, iz, do, s / so, bez, za, pri (в, на, из, до, с, без, за, при).", "hint_en": "One character, identical to Russian  Check the lesson vocabulary: v / vo, na, iz, do, s / so, bez, za, pri.", "xp": 20}]}$j$::jsonb) ON CONFLICT (id) DO UPDATE SET category_id = EXCLUDED.category_id, sort_order = EXCLUDED.sort_order, payload = EXCLUDED.payload;
